import { useEffect, useMemo, useState } from "react";
import {
    getPaymentsByContract,
    createPaymentForContract,
    markPaymentPaid,
    deletePayment,
} from "../api";
import { useAuth } from "../AuthContext";

const money = (v) => (Number(v || 0)).toLocaleString("vi-VN") + " ₫";
const fmtDate = (s) => (s ? new Date(s).toLocaleDateString("vi-VN") : "-");

const METHODS = [
    { label: "Tiền mặt", value: "CASH" },
    { label: "Chuyển khoản", value: "BANK_TRANSFER" },
    { label: "Khác", value: "OTHER" },
];

const STATUS_BADGE = {
    PAID: "bg-green-100 text-green-700",
    UNPAID: "bg-amber-100 text-amber-700",
    CANCELLED: "bg-gray-100 text-gray-600",
};

function normalizeList(data) {
    // Hỗ trợ cả dạng mảng lẫn Page<?> từ BE
    if (Array.isArray(data)) return { list: data, pages: 1 };
    return { list: data?.content || [], pages: data?.totalPages || 1 };
}

export default function Payments() {
    const { user } = useAuth();
    const role = (user?.role || "").toUpperCase();

    // Quyền hiển thị/thao tác đúng với BE
    const canView = ["ADMIN", "ACCOUNTANT", "SALES"].includes(role);
    const canCreate = ["ADMIN", "ACCOUNTANT", "SALES"].includes(role); // SALES: chỉ hợp đồng mình (BE check)
    const canMarkPaid = ["ADMIN", "ACCOUNTANT"].includes(role);
    const canDelete = ["ADMIN", "SALES"].includes(role); // SALES: chỉ UNPAID + owner (BE check)

    const [contractId, setContractId] = useState("");
    const [rows, setRows] = useState([]);
    const [totalPages, setTotalPages] = useState(1);
    const [loading, setLoading] = useState(false);
    const [msg, setMsg] = useState("");

    const [form, setForm] = useState({
        amount: "",
        method: "BANK_TRANSFER",
        planDate: "",
        note: "",
    });

    const formValid = useMemo(() => Number(form.amount) > 0 && !!form.method, [form]);

    useEffect(() => {
        if (!canView) return;
        if (!contractId) {
            setRows([]);
            setTotalPages(1);
            return;
        }
        loadData(contractId);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [contractId, canView]);

    async function loadData(cid) {
        setLoading(true);
        setMsg("");
        try {
            const res = await getPaymentsByContract(String(cid).trim());
            const n = normalizeList(res?.data || []);
            setRows(n.list);
            setTotalPages(n.pages);
        } catch (e) {
            setRows([]);
            setTotalPages(1);
            setMsg(e?.response?.data?.message || "Không tải được danh sách thanh toán.");
        } finally {
            setLoading(false);
        }
    }

    if (!canView) {
        return (
            <div className="p-6">
                <h1 className="text-2xl font-semibold">Thanh toán</h1>
                <p className="mt-3 text-sm text-gray-600">Bạn không có quyền xem trang này.</p>
            </div>
        );
    }

    const handleCreate = async (e) => {
        e.preventDefault();
        setMsg("");
        if (!contractId) return setMsg("Vui lòng nhập ID hợp đồng trước.");
        if (!formValid) return setMsg("Vui lòng nhập số tiền > 0 và chọn phương thức.");

        try {
            await createPaymentForContract(String(contractId).trim(), {
                amount: Number(form.amount),
                method: form.method, // CASH | BANK_TRANSFER | OTHER
                planDate: form.planDate || null,
                note: form.note || null,
            });
            setForm({ amount: "", method: "BANK_TRANSFER", planDate: "", note: "" });
            await loadData(contractId);
            setMsg("Đã tạo khoản thu.");
        } catch (e) {
            setMsg(e?.response?.data?.message || "Không tạo được khoản thu.");
        }
    };

    const doMarkPaid = async (paymentId) => {
        setMsg("");
        try {
            await markPaymentPaid(paymentId, {}); // nếu không truyền, BE sẽ set paymentDate = hôm nay
            await loadData(contractId);
            setMsg("Đã xác nhận đã thu.");
        } catch (e) {
            setMsg(e?.response?.data?.message || "Không thể xác nhận đã thu.");
        }
    };

    const doDelete = async (paymentId) => {
        if (!window.confirm("Xoá khoản thu này? (Chỉ xoá được khi CHƯA THU)")) return;
        setMsg("");
        try {
            await deletePayment(paymentId);
            await loadData(contractId);
            setMsg("Đã xoá khoản thu.");
        } catch (e) {
            setMsg(e?.response?.data?.message || "Không xoá được khoản thu.");
        }
    };

    return (
        <div className="p-6 space-y-6">
            <div className="flex items-end gap-3">
                <div>
                    <label className="block text-sm text-gray-600 mb-1">ID Hợp đồng</label>
                    <input
                        value={contractId}
                        onChange={(e) => setContractId(e.target.value)}
                        placeholder="Nhập ID hợp đồng (số) để tải các đợt thanh toán"
                        className="px-3 py-2 border rounded-lg w-64 focus:outline-none focus:ring"
                    />
                </div>
                <button
                    onClick={() => contractId && loadData(contractId)}
                    className="px-4 py-2 rounded-xl bg-blue-600 text-white hover:bg-blue-700"
                >
                    Tải thanh toán
                </button>
            </div>

            {msg && (
                <div className="text-sm text-amber-700 bg-amber-50 border border-amber-200 rounded-lg p-3">
                    {msg}
                </div>
            )}

            {/* Form tạo đợt thanh toán */}
            {canCreate && (
                <form
                    onSubmit={handleCreate}
                    className="grid grid-cols-1 md:grid-cols-4 gap-4 bg-white rounded-2xl p-4 shadow"
                >
                    <div>
                        <label className="block text-sm text-gray-600 mb-1">Số tiền</label>
                        <input
                            type="number"
                            min={0}
                            step={1000}
                            value={form.amount}
                            onChange={(e) => setForm((s) => ({ ...s, amount: e.target.value }))}
                            placeholder="Ví dụ: 10000000"
                            className="px-3 py-2 border rounded-lg w-full focus:outline-none focus:ring"
                        />
                    </div>

                    <div>
                        <label className="block text-sm text-gray-600 mb-1">Phương thức</label>
                        <select
                            value={form.method}
                            onChange={(e) => setForm((s) => ({ ...s, method: e.target.value }))}
                            className="px-3 py-2 border rounded-lg w-full focus:outline-none focus:ring"
                        >
                            {METHODS.map((m) => (
                                <option key={m.value} value={m.value}>
                                    {m.label}
                                </option>
                            ))}
                        </select>
                    </div>

                    <div>
                        <label className="block text-sm text-gray-600 mb-1">Ngày dự kiến thu</label>
                        <input
                            type="date"
                            value={form.planDate}
                            onChange={(e) => setForm((s) => ({ ...s, planDate: e.target.value }))}
                            className="px-3 py-2 border rounded-lg w-full focus:outline-none focus:ring"
                        />
                    </div>

                    <div>
                        <label className="block text-sm text-gray-600 mb-1">Ghi chú</label>
                        <input
                            value={form.note}
                            onChange={(e) => setForm((s) => ({ ...s, note: e.target.value }))}
                            placeholder="Nhập ghi chú (tuỳ chọn)"
                            className="px-3 py-2 border rounded-lg w-full focus:outline-none focus:ring"
                        />
                    </div>

                    <div className="md:col-span-4">
                        <button
                            type="submit"
                            disabled={!formValid || !contractId}
                            className="px-4 py-2 rounded-xl bg-emerald-600 text-white hover:bg-emerald-700 disabled:opacity-50"
                        >
                            Thêm đợt thanh toán
                        </button>
                    </div>
                </form>
            )}

            {/* Danh sách thanh toán */}
            <div className="bg-white rounded-2xl shadow overflow-hidden">
                <div className="px-4 py-3 border-b">
                    <div className="font-semibold">
                        Danh sách thanh toán {loading && <span className="text-sm text-gray-500">Đang tải…</span>}
                    </div>
                </div>

                <div className="divide-y">
                    <div className="grid grid-cols-12 px-4 py-2 text-xs font-medium text-gray-500">
                        <div className="col-span-2">Mã HĐ</div>
                        <div className="col-span-2">Ngày dự kiến/Ngày trả</div>
                        <div className="col-span-2">Số tiền</div>
                        <div className="col-span-2">Phương thức</div>
                        <div className="col-span-2">Trạng thái</div>
                        <div className="col-span-2 text-right">Thao tác</div>
                    </div>

                    {rows.length === 0 && (
                        <div className="px-4 py-8 text-center text-sm text-gray-500">Chưa có dữ liệu.</div>
                    )}

                    {rows.map((p) => {
                        const status = (p.status || "UNPAID").toUpperCase();
                        const badge = STATUS_BADGE[status] || "bg-gray-100 text-gray-700";
                        return (
                            <div key={p.id} className="grid grid-cols-12 px-4 py-3 items-center">
                                <div className="col-span-2 truncate">{contractId}</div>
                                <div className="col-span-2">
                                    <div className="text-sm">{fmtDate(p.planDate)}</div>
                                    <div className="text-xs text-gray-500">
                                        {p.paymentDate ? `Trả: ${fmtDate(p.paymentDate)}` : ""}
                                    </div>
                                </div>
                                <div className="col-span-2">{money(p.amount)}</div>
                                <div className="col-span-2">{p.method}</div>
                                <div className="col-span-2">
                  <span className={`px-2 py-1 rounded-full text-xs ${badge}`}>
                    {status === "PAID"
                        ? "ĐÃ THU"
                        : status === "UNPAID"
                            ? "CHƯA THU"
                            : status}
                  </span>
                                </div>
                                <div className="col-span-2 text-right space-x-2">
                                    {canMarkPaid && status === "UNPAID" && (
                                        <button
                                            className="px-3 py-1 rounded-lg bg-blue-600 text-white hover:bg-blue-700"
                                            onClick={() => doMarkPaid(p.id)}
                                        >
                                            Xác nhận đã thu
                                        </button>
                                    )}
                                    {canDelete && status === "UNPAID" && (
                                        <button
                                            className="px-3 py-1 rounded-lg bg-rose-600 text-white hover:bg-rose-700"
                                            onClick={() => doDelete(p.id)}
                                        >
                                            Xoá
                                        </button>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                </div>

                {/* Nếu dùng phân trang từ BE: totalPages hiển thị tham khảo */}
                <div className="px-4 py-3 text-xs text-gray-500">
                    Trang 1/{totalPages}
                </div>
            </div>
        </div>
    );
}
